16	          <KialiIcon.Info className={infoStyle} />
17	        </Tooltip>
18	      </div>
19	    </>
20	  ];
21	};
22	
23	export const renderWaypointSimpleLabel = (bgsize?: string): React.ReactNode => {
24	  const badgeSize = bgsize === 'global' || bgsize === 'sm' ? bgsize : 'global';
25	  const tooltip = <div>{t('This workload is an Istio Ambient waypoint proxy')}</div>;
26	
27	  return [
28	    <>
29	      <PFBadge
30	        badge={PFBadges.Waypoint}
31	        position={TooltipPosition.top}
32	        size={badgeSize}
33	        tooltip={tooltip}
34	        style={{ marginLeft: '5px' }}
35	      />
36	    </>
37	  ];
38	};

